const raw = $json.choices[0].message.content;
const parsed = JSON.parse(raw);
const state = $getWorkflowStaticData('global');
const chatId = $('When Called by Жора').first().json.original_data.chat_id;

state[`options_${chatId}`] = {
  options: parsed.options,
  expires: Date.now() + 300000
};

const text = `🤔 Уточни что нужно:\n\n${parsed.options.map(o => `${o.num}. ${o.emoji} ${o.title}`).join('\n')}\n\nОтветь цифрой (1–3) или напиши заново.`;

return [{ json: { message: text, chat_id: chatId } }];
